head.script:
// 전역변수 선언
scwin.RPTTYP = ""

scwin.onpageload = function () {

    const {tabId, rowIndex, pFrame}  = $c.data.getParameter();
    const openerObj = opener.$p.getComponentById(pFrame).scope;
    const dlt_fl = openerObj.ds_fl;
    const dlt_flc = openerObj.ds_flc;

    // [위치생성] 버튼 hide
    $c.gus.cfDisableObjects([btn_save]);
    btn_save.setStyle("display", "none");

    const flData = dlt_fl.getRowJSON(rowIndex);
    const {realOn,realOff,repClntNo,realPdaYn,steelVehclYn,statuss,dmCoshippingNo,railroadAdptDstCd} = flData;

    if (realOn != "" || realOff != "") {
        if (repClntNo == "000012" && realPdaYn == "0" && steelVehclYn == "1") {

            // [위치생성] 버튼 show
            $c.gus.cfEnableObjects([btn_save]);
            btn_save.setStyle("display", "");
        }
    }

    if ($c.util.isEmpty(rowIndex)) {
        $c.win.alert('화물정보가 선택되지 않았습니다. 화물정보를 선택하여 주시기 바랍니다.').then(() => {
            window.close();
        });
        return;
    }

    const toDate = $c.date.getServerDateTime("yyyyMMdd");
    ed_qryDt1.setValue(toDate);
    ed_qryDt2.setValue(toDate);
    ed_qryDt3.setValue(toDate);
    ed_qryDt4.setValue(toDate);

    if (tabId == 'cargo') {
        // 벌크 화물  (합적화물인 경우 출도착 보고가 같이 된다.)

        grp_cargo.show();
        grp_cont.hide();

        tab_cargoCont.disableTab(1);

        if (statuss == '대기') {
            $c.win.alert('[TMS오류] 배차되지 않은 화물은 운송보고를 할수 없습니다.확인 바랍니다.').then(() => {
                window.close();
            });
            return;
        }

        if (dmCoshippingNo != "") {
            // 합적화물
            const matchArr = dlt_fl.getMatchedJSON("dmCoshippingNo", dmCoshippingNo, true);

            // 데이터 가공
            matchArr.forEach(data => {
                data.onDt  = ((data.onDt ?? '')  + (data.onHh ?? '')).replace(/[-:]/g,'');
                data.offDt = ((data.offDt ?? '') + (data.offHh ?? '')).replace(/[-:]/g,'');
            });

            ds_fl.setJSON(matchArr);

        } else {
            // 합적되지 않은 화물

            // 데이터 가공
            flData.onDt = ((flData.onDt ?? '')  + (flData.onHh ?? '')).replace(/[-:]/g,'');
            flData.offDt = ((flData.offDt ?? '')  + (flData.offHh ?? '')).replace(/[-:]/g,'');

            ds_fl.setJSON([flData]);
        }

        ds_fl.modifyAllStatus("C");
        gr_fl_blk.setFocusedCell(ds_fl.getTotalRow()-1, "idx");

        // 데이타 셋팅 후 주문번호 Ascending 정렬         		
        ds_fl.multisort({sortIndex: "idx", sortOrder: "1"});

        // 실상차일자 | 상차시간
        if (realOn != "") {
            temp = realOn.replace(/[-:]/g,'');
            ed_qryDt1.setValue(temp.slice(0,8));
            ed_onDt_blk.setValue(temp.slice(9,13));
        }

        // 실상차수량
        if (ds_fl.getCellData(0, "realOnQty") != 0) {
            ed_onQty_blk.setValue(ds_fl.getCellData(0, "realOnQty"));
        } else {
            // 수량의 합계로 대처
            ed_onQty_blk.setValue(ds_fl.getColSum("qty"));
        }

        // 실하차일자 | 하차시간
        if (realOff != "") {
            temp = realOff.replace(/[-:]/g,'');
            ed_qryDt2.setValue(temp.slice(0,8));
            ed_offDt_blk.setValue(temp.slice(9,13));
        }

        // 실상차중량
        if (ds_fl.getCellData(0, "realOnWt") != 0) {
            ed_onWt_blk.setValue(ds_fl.getCellData(0, "realOnWt"));
        } else {
            // 중량의 합계로 대처
            ed_onWt_blk.setValue(ds_fl.getColSum("wt"));
        }

        // 운송구분
        if (railroadAdptDstCd == "철송") lc_trans_type.setValue("R");

        // 상차 시간이 있으면  하차보고가 된다.
        if (ed_onDt_blk.getValue() != "" && ed_offDt_blk.getValue() == "")
            scwin.RPTTYP = "2";

        // 조회건수 설정
        tbx_totalCargo.setValue(ds_fl.getTotalRow())

    } else { //컨테이너번호

        grp_cargo.hide();
        grp_cont.show();
        btn_save.hide();

        tab_cargoCont.disableTab(0);
        tab_cargoCont.setSelectedTabIndex(1);

        const flcData = dlt_flc.getRowJSON(rowIndex);
        const {statuss,wrkStpCd,dptWrkPlCd,arvWrkPlCd,realOn,realOff,cntrNo,cntrSealNo} = flcData;

        let msg = "";
        if (statuss == '대기') {
            msg = '[TMS오류] 배차되지 않은 화물은 운송보고를 할수 없습니다.확인 바랍니다.';
        } else if (wrkStpCd == '0002' && dptWrkPlCd.substr(1,1) == 'C') {
            msg = '[TMS오류] 작업단계가 운송이고 출발지가 CY일 경우에는 운송보고를 할 수 없습니다.';
        } else if (wrkStpCd == '0003' && arvWrkPlCd.substr(1, 1) == 'C') {
            msg = '[TMS오류] 작업단계가 회수이고 도착지가 CY일 경우에는 운송보고를 할 수 없습니다.';
        } else if (wrkStpCd == '0001' && dptWrkPlCd == '7P1' && arvWrkPlCd == '7R06') {
            msg = '[TMS오류]작업단계가 셔틀일 경우 운송보고를 할 수 없습니다.';
        }

        if (!$c.util.isEmpty(msg)) {
            $c.win.alert(msg).then(() => {
                window.close();
            });
            return;
        }

        // 데이터 가공
        flcData.onDd = ((flcData.onDd ?? '')  + (flcData.onHh ?? '')).replace(/[-:]/g,'');
        flcData.offDd = ((flcData.offDd ?? '')  + (flcData.offHh ?? '')).replace(/[-:]/g,'');

        ds_flc.setJSON([flcData]);
        ds_flc.modifyAllStatus("C");
        gr_fl_cntr.setFocusedCell(ds_flc.getTotalRow()-1, "idx");

        let temp;

        // 실상차일자 | 상차시간
        if (realOn != "") {
            temp = realOn.replace(/[-:]/g,'');
            ed_qryDt3.setValue(temp.slice(0,8));
            ed_onDt_cnt.setValue(temp.slice(9,13));
        }

        // 컨테이너 번호
        ed_cntrNo_cnt.setValue(cntrNo);

        // 실하차일자 | 하차시간
        if (realOff != "") {
            temp = realOff.replace(/[-:]/g,'');
            ed_qryDt4.setValue(temp.slice(0,8));
            ed_offDt_cnt.setValue(temp.slice(9,13));
        }

        // 실번호
        ed_sealNo_cnt.setValue(cntrSealNo);

        // 상차 시간이 있으면 하차보고가 된다.			
        if (ed_onDt_cnt.getValue() != "" && ed_offDt_cnt.getValue() == "")
            scwin.RPTTYP = "2";

        // 조회건수 설정
        tbx_totalCont.setValue(ds_flc.getTotalRow());

    }
};

/**
 * [닫기]
 */
scwin.btn_close_onclick = function (e) {
    window.close();
};

/**
 * [보고저장] / [취소]
 */
scwin.f_Save = async function (type) {
    const {tabId}  = $c.data.getParameter();

    let vFlIdxs;

    if (tabId == 'cargo') {
        if (ed_qryDt1.getValue() == "") {
            $c.win.alert("실상차일자을 입력하세요").then(() => {
                ed_qryDt1.focus();
            });
            return;
        }

        if (ed_qryDt2.getValue() == "") {
            $c.win.alert("실하차일자을 입력하세요").then(() => {
                ed_qryDt2.focus();
            });
            return;
        }

        if (ed_onQty_blk.getValue() == "" && ed_onWt_blk.getValue() == "") {
            $c.win.alert("실상차 수량이나 실상차 중량을 입력하세요.").then(() => {
                ed_onQty_blk.focus();
            });
            return;
        }
        if (ed_onDt_blk.getValue() == "" || ed_offDt_blk.getValue() == "") {
            $c.win.alert("시간을 모두 입력하세요").then(() => {
                ed_onDt_blk.focus();
            });
            return;
        }

    } else {

        if (ed_qryDt3.getValue() == "") {
            $c.win.alert("실상차일자을 입력하세요").then(() => {
                ed_qryDt3.focus();
            });
            return;
        }

        if ($c.str.trim(ed_cntrNo_cnt.getValue()) == "") {
            $c.win.alert("컨테이너 번호를 입력하세요").then(() => {
                ed_cntrNo_cnt.focus();
            });
            return;
        }

        // 컨테이너 번호 정합성 체크
        if (!scwin.checkCntrNo(ed_cntrNo_cnt.getValue().toUpperCase())) {
            if (!await $c.win.confirm("유효한 컨테이너가 아닙니다.\n\n계속 진행하시겠습니까?")) {
                ed_cntrNo_cnt.setValue("");
                ed_cntrNo_cnt.focus();
                return;
            }
        }

        if ((ed_onDt_cnt.getValue() == "" && ed_offDt_cnt.getValue() != "") ||
            (ed_onDt_cnt.getValue() == "" && ed_offDt_cnt.getValue() == "")) {
            $c.win.alert("상차시간을 입력하세요").then(() => {
                ed_onDt_cnt.focus();
            });
            return;
        }

    }

    if (tabId == 'cargo') {

        for(let i=0; i<ds_fl.getTotalRow(); i++) {

            const iRow = ds_PdaReport.insertRow();

            if (ed_onDt_blk.getValue() != "" && ed_offDt_blk.getValue() == "") {
                // 상차보고
                ds_PdaReport.setCellData(iRow, "rtpTyp", '1');
            } else if (scwin.RPTTYP == "2") {
                // 하차보고
                ds_PdaReport.setCellData(iRow, "rtpTyp", '2');
            } else if (ed_onDt_blk.getValue() != "" && ed_offDt_blk.getValue() != "") {
                // 상하차보고
                ds_PdaReport.setCellData(iRow, "rtpTyp", '3');
            } else {
                ds_PdaReport.setCellData(iRow, "rtpTyp", '3');
            }

            ds_PdaReport.setCellData(iRow, "flFlag", '1');
            ds_PdaReport.setCellData(iRow, "realOnQty", ed_onQty_blk.getValue());
            ds_PdaReport.setCellData(iRow, "realOnWt", ed_onWt_blk.getValue());

            if (type == "SAVE") {
                ds_PdaReport.setCellData(iRow, "realOnDt", ed_qryDt1.getValue() + ed_onDt_blk.getValue());
                ds_PdaReport.setCellData(iRow, "realOffDt", ed_qryDt2.getValue() + ed_offDt_blk.getValue());
            } else {
                ds_PdaReport.setCellData(iRow, "realOnDt", ed_qryDt1.getValue() + "0000");
                ds_PdaReport.setCellData(iRow, "realOffDt", ed_qryDt2.getValue() + "0000");
                ds_PdaReport.setCellData(iRow, "rtpTyp", '3');
            }

            // 선택된 화물 idx
            vFlIdxs = ds_fl.getCellData(iRow, "idx").split('-');
            ds_PdaReport.setCellData(iRow, "ez202Idx", vFlIdxs[0]);
            ds_PdaReport.setCellData(iRow, "dtlIdx", vFlIdxs[1]);

            // 운송구분
            ds_PdaReport.setCellData(iRow, "railroadAdptDstCd", lc_trans_type.getValue());
        }

        // 합적화물일경우, 실상차수량 및 실상차중량 세팅
        if (ds_fl.getTotalRow() > 1) {  
            for(let i=0; i<ds_fl.getTotalRow(); i++) {
                ds_PdaReport.setCellData(i, "realOnQty", 0);
                ds_PdaReport.setCellData(i, "realOnWt", 0);
            }
            ds_PdaReport.setCellData(0, "realOnQty", ed_onQty_blk.getValue());
            ds_PdaReport.setCellData(0, "realOnWt", ed_onWt_blk.getValue());
        }

    } else {

        const iRow = ds_PdaReport.insertRow();

        if (ed_onDt_cnt.getValue() != "" && ed_offDt_cnt.getValue() == "") { //상차보고
            ds_PdaReport.setCellData(iRow, "rtpTyp", '1');
        } else if (scwin.RPTTYP == "2") {//하차보고
            ds_PdaReport.setCellData(iRow, "rtpTyp", '2');
        } else if (ed_onDt_cnt.getValue() != "" && ed_offDt_cnt.getValue() != "") { //상하차보고
            ds_PdaReport.setCellData(iRow, "rtpTyp", '3');
        } else {
            ds_PdaReport.setCellData(iRow, "rtpTyp", '3');
        }

        ds_PdaReport.setCellData(iRow, "flFlag", '2');
        ds_PdaReport.setCellData(iRow, "cntrNo", ed_cntrNo_cnt.getValue().toUpperCase());
        ds_PdaReport.setCellData(iRow, "sealNo", ed_sealNo_cnt.getValue());

        if (type == "SAVE") {
            ds_PdaReport.setCellData(iRow, "realOnDt", ed_qryDt3.getValue() + ed_onDt_cnt.getValue());
            ds_PdaReport.setCellData(iRow, "realOffDt", ed_qryDt4.getValue() + ed_offDt_cnt.getValue());
        } else {
            ds_PdaReport.setCellData(iRow, "realOnDt", ed_qryDt3.getValue() + "0000");
            ds_PdaReport.setCellData(iRow, "realOffDt", ed_qryDt4.getValue() + "0000");
            ds_PdaReport.setCellData(iRow, "rtpTyp", '3');
        }

        // 선택된 화물 idx
        vFlIdxs = ds_flc.getCellData(0, "idx").split('-');
        ds_PdaReport.setCellData(iRow, "ez202Idx", vFlIdxs[0]);
        ds_PdaReport.setCellData(iRow, "dtlIdx", vFlIdxs[1]);
    }

    // 벌크화물만 해당
    for(let i=0; i<ds_fl.getRowCount(); i++) {
        if (type == "SAVE") {
            if (ds_PdaReport.getCellData(i, "realOnDt") >= ds_PdaReport.getCellData(i, "realOffDt")) {
                $c.win.alert("실하차일시는 실상차일시 이후여야 합니다.");
                return;
            }
        }
    }

    $c.sbm.execute(sbm_PdaReport);

};

/**
 * [운송보고] callback
 */
scwin.sbm_PdaReport_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code == 0) {

        const pFrame = opener.$p.getComponentById($c.data.getParameter().pFrame);
        const msg = ds_result.getCellData(0, "outMsg");
        if (!$c.util.isEmpty(msg)) {
            $c.win.alert(msg).then(() => {
                pFrame.scope.scwin.reflashdata();
                window.close();
            })
        }
    }
};

/**
 * [위치생성]
 * 
 * 2026.03.13 (하상진님 요청으로 동작 제어)
 * 우편번호 조회 후 실행하는 sbm_zipcode 서브미션 후처리(scwin.f_RetrievePosition)를 보면 데이터 확인이 안됨
 */
scwin.f_position = function (e) {

    return;

    const {...data} = ds_fl.getRowJSON(0);
    var stDtm = data.dptDt;
    var endDtm = data.arvDt;
    var sDateStr = stDtm.trim();
    var eDateStr = endDtm.trim();
    var aaa = sDateStr.substring(0, 8);
    var bbb = eDateStr.substring(0, 8);

    // 좌표 소수점 제거 (버림)
    // sql에서 TRUNC 해오는데 왜 .0 이 붙어서 보이는지 모르겠음
    const dptXPos = Math.trunc(data.dptXPos);
    const dptYPos = Math.trunc(data.dptYPos);
    const arvXPos = Math.trunc(data.arvXPos);
    const arvYPos = Math.trunc(data.arvYPos);

    var vZip = "";
    var vTitle = "우편번호,우편번호,동이름";

    if (dptXPos == "" || dptYPos == "") {
        $c.win.alert("출발지 위치정보 없음").then(() => {
            udc_zipCode.setSelectId("retrieveZipList_tpro");
            udc_zipCode.cfCommonPopUp(scwin.udc_zipCode_callBack_Func
                , vZip, '', 'T', null, vTitle, null, null, null, null, null, null, null, null, null, null, null);
        });

    } else if (arvXPos == "" || arvYPos == "") {
        $c.win.alert("도착지 위치정보 없음").then(() => {
            udc_zipCode.setSelectId("retrieveZipList_tpro")
            udc_zipCode.cfCommonPopUp(scwin.udc_zipCode2_callBack_Func
                , vZip, '', 'T', null, vTitle, null, null, null, null, null, null, null, null, null, null, null);
        });

    } else {

        if (data.dptDt == "" || data.dptHh == "" || data.arvDt == "" || data.arvHh == "") {
            $c.win.alert("운송보고 후 입력하세요");
            return false;

        } else {
            if ($c.date.diffDate(aaa, bbb) > 4) {
                $c.win.alert("7일 이상의 기간은 경로생성이 안됩니다");
                return false;

            } else if (data.pdaNo == "") {
                $c.win.alert("PDA번호가 없습니다");
                return false;

            } else {
                const iRow = ds_CreateLocation.insertRow();

                ds_CreateLocation.setCellData(iRow, "fromXPos", dptXPos);
                ds_CreateLocation.setCellData(iRow, "fromYPos", dptYPos);
                ds_CreateLocation.setCellData(iRow, "toXPos", arvXPos);
                ds_CreateLocation.setCellData(iRow, "toYPos", arvYPos);
                ds_CreateLocation.setCellData(iRow, "dptDt", data.dptDt);
                ds_CreateLocation.setCellData(iRow, "dptHh", data.dptHh);
                ds_CreateLocation.setCellData(iRow, "arvDt", data.arvDt);
                ds_CreateLocation.setCellData(iRow, "arvHh", data.arvHh);
                ds_CreateLocation.setCellData(iRow, "vehclNo", data.vehclNo);
                ds_CreateLocation.setCellData(iRow, "pdaNo", data.pdaNo);
                ds_CreateLocation.setCellData(iRow, "picNm", data.vehclPicNm);
                ds_CreateLocation.setCellData(iRow, "handphoneNo", data.handphoneNo);

                $c.sbm.execute(sbm_CreateLocation);
            }
        }
    }
};

/**
 * [위치생성] callback
 */
scwin.sbm_CreateLocation_submitdone = function(e) {

};

/**
 * 출발지 위치정보 POPUP callback
 */
scwin.udc_zipCode_callBack_Func = function (rtnList) {
    if (rtnList != null) {
        var zipCode = "";
        zipCode = rtnList[0];
        scwin.f_RetrievePosition(zipCode, "dpt");
    }
};

/**
 * 도착지 위치정보 POPUP callback
 */
scwin.udc_zipCode2_callBack_Func = function (rtnList) {
    if (rtnList != null) {
        var zipCode = "";
        zipCode = rtnList[0];
        scwin.f_RetrievePosition(zipCode, "arv");
    }
};

/**
 * 위치조회 submission
 */
scwin.f_RetrievePosition = async function (zipCd, type) {
    if (zipCd != "" && zipCd != null) {
        var condition = {
            ZIP_CD: zipCd
        };

        dma_zipcode.setEmptyValue();
        dma_zipcode.setJSON(condition);

        let ret = await $c.sbm.execute(sbm_zipcode);

        if (ret.responseJSON.resultDataSet[0].Code == 0) {
            ds_Position.setJSON(ret.responseJSON.GAUCE);
        }

        const colXPos = type == "dpt"? "dptXPos" : "arvXPos";
        const colYPos = type == "dpt"? "dptYPos" : "arvYPos";

        for(i = 0; i < ds_fl.getRowCount(); i++) {
            ds_fl.setCellData(i, colXPos, ds_Position.getCellData(0, "xpos"));
            ds_fl.setCellData(i, colYPos, ds_Position.getCellData(0, "ypos"));
        }
    }
};

/**
 * 컨테이너 번호 정합성 체크
 */
scwin.checkCntrNo = function (parCntrNo) {
    const tempData = "1012131415161718192021232425262728293031323435363738";
    const cntrNo = $c.str.trim(parCntrNo);

    if (cntrNo == "" || cntrNo.length != 11) {
        return false;
    } else {

        const re = /^[A-Z]{4}[0-9]{7}$/;

        if (!re.test(cntrNo)) {
            return false;
        }

        var tempPos1 = tempData.substr((cntrNo.charCodeAt(0) - 65) * 2, 2) * 1;
        var tempPos2 = tempData.substr((cntrNo.charCodeAt(1) - 65) * 2, 2) * 2;
        var tempPos3 = tempData.substr((cntrNo.charCodeAt(2) - 65) * 2, 2) * 4;
        var tempPos4 = tempData.substr((cntrNo.charCodeAt(3) - 65) * 2, 2) * 8;

        var tempSum = tempPos1 + tempPos2 + tempPos3 + tempPos4
            + (cntrNo.substr(4, 1) * 16)
            + (cntrNo.substr(5, 1) * 32)
            + (cntrNo.substr(6, 1) * 64)
            + (cntrNo.substr(7, 1) * 128)
            + (cntrNo.substr(8, 1) * 256)
            + (cntrNo.substr(9, 1) * 512);

        var tempMod = (tempSum % 11) + "";

        if (cntrNo.substr(10, 1) != tempMod.charAt(tempMod.length - 1)) {
            return false;
        }
    }

    return true;
};

/**
 * 날짜 format
 */
scwin.format_date = function(val) {
    return $c.date.formatDateTime(val, "yyyy/MM/dd");
};

/**
 * 날짜 format
 */
scwin.format_ymdhm = function(val) {
    return $c.date.formatDateTime(val, "yyyy/MM/dd HH:mm:ss").slice(0, 16);
};

/**
 * 날짜 format
 */
scwin.format_dashToSlash = function(val) {
    return val != ""? val.replace(/-/g, "/") : val;
};

/**
 * 소수점 버리고 세자리 쉼표 format
 */
scwin.format_parseInt = function(val) {
    return $c.num.formatNumber(parseInt(val));
};
